|name=Force phantom
|alternate=[[Force ghost/Legends|Force ghost]] manifestation {{C|mistakenly}}<ref name="Exile">''[[Legacy of the Force: Exile]]''</ref>
|alignment=[[Dark side of the Force/Legends|Dark side of the Force]]<ref name="Betrayal">''[[Legacy of the Force: Betrayal]]''</ref>
